<template>
	<div
		class="container"
		ref="container"></div>
</template>

<script>
	import * as d3 from 'd3';
	import data from './assets/flare-2.simple.json'
	// import data from './assets/flare-2.json'

	export default {
		mounted(){
			let 
				container = this.$refs.container,
				width = this.width = container.clientWidth,
				height = this.height = container.clientHeight,
				format = d3.format(","),
				columns = [
					{
						label: "Size", 
						value: d => d.value, 
						format, 
						x: 280
					}, {
						label: "Count", 
						value: d => d.children ? 0 : 1, 
						format: (value, d) => d.children ? format(value) : "-", 
						x: 340
					}
				],

				nodeSize = 17,
				i = 0,
				root = d3.hierarchy(data).eachBefore(d => d.index = i++),
				nodes = root.descendants(),

				svg = d3.select(container)
					.append('svg')
		      .attr("viewBox", [-nodeSize / 2, -nodeSize * 3 / 2, width, height])
					.attr( 'width', width )
					.attr( 'height', height )
					.style("font", "12px sans-serif"),

				link = svg.append("g")
					.attr("fill", "none")
					.attr("stroke", "#999")
					.selectAll("path")
					.data(root.links())
					.join("path")
					.attr("d", d => `
						M${d.source.depth * nodeSize},${d.source.index * nodeSize}
						V${d.target.index * nodeSize}
						h${nodeSize}
					`),
				 node = svg.append("g")
					.selectAll("g")
					.data(nodes)
					.join("g")
					.attr("transform", d => `translate(0,${d.index * nodeSize})`);

		  node.append("circle")
		      .attr("cx", d => d.depth * nodeSize)
		      .attr("r", 2.5)
		      .attr("fill", d => d.children ? null : "#999");

		  node.append("text")
		      .attr("dy", "0.32em")
		      .attr("x", d => d.depth * nodeSize + 6)
		      .text(d => d.data.name);

		  node.append("title")
		      .text(d => d.ancestors().reverse().map(d => d.data.name).join("/"));

		  for (const {label, value, format, x} of columns) {
		    svg.append("text")
		        .attr("dy", "0.32em")
		        .attr("y", -nodeSize)
		        .attr("x", x)
		        .attr("text-anchor", "end")
		        .attr("font-weight", "bold")
		        .text(label);

		    node.append("text")
		        .attr("dy", "0.32em")
		        .attr("x", x)
		        .attr("text-anchor", "end")
		        .attr("fill", d => d.children ? null : "#555")
		      .data(root.copy().sum(value).descendants())
		        .text(d => format(d.value, d));
		  }
		}
	}

</script>